member.example:
Bind the Transform local scale using a serialized binder field — the target Transform is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TransformScaleBinder _scale;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _scale;
    }


Bind the Transform local scale by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Transform _target;
        
        private TransformScaleBinder Scale =>
            new(_target, converter: null);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _scale;
    }

Switch the Transform local scale between two values using a serialized binder field — the target Transform is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TransformScaleSwitcherBinder _isVisible;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isVisible;
    }


Switch the Transform local scale between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private Transform _target;
        
        [SerializeField]
        private Vector3 _visibleScale;
        
        [SerializeField]
        private Vector3 _hiddenScale;
        
        private TransformScaleSwitcherBinder IsVisible => new(
            _target, _visibleScale, _hiddenScale, converter: null);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isVisible;
    }
